INSERT INTO `system_setting` (`config_name`, `config_value`, `description`) VALUES ( 'var.pro_before_buy_description', '\n购买前须知:\r\n\n为了保证付费用户和作者的权益， 随着版本的升级，激活验证机制，可能会随升级而更新，所以更换新版本可能需要用户手动再次激活（在激活期内的不用再次付费）。\n\n请注意软件目前不支持离线激活，请在有网环境下使用。**标准功能** 无需登录即可使用，使用 **PRO功能** 的功能软件必须要登录。 购买后不支持退款，请谨慎购买，请不要将账号分享给其他用户，如果检测一个账号多个软件激活使用，将收回**PRO权益**，不退款！', 'Pro购买前说明');
INSERT INTO `system_setting` (`config_name`, `config_value`, `description`) VALUES ( 'var.pro_func_description', '<div style=\"color:red;display:flex;justify-content:center\">\n\n\n| 功能                                                                          | 标准版 | Pro版 |\n| ----------------------------------------------------------------------------- | ------ | ----- |\n| <div style=\"color:red;display:flex;justify-content:center\">基础图标管理</div> | ✅     | ✅    |\n| 多账号                                                                        | ✅     | ✅    |\n| 一键切换内外网                                                                | ✅     | ✅    |\n| **系统状态组件**                                                              | ✅     | ✅    |\n| 开放API（开发中）                                                             | ✅     | ✅    |\n| 自定义项目图标（开发中）                                                      | ❌     | ✅    |\n| 自定义登录页的文字（开发中）                                                  | ❌     | ✅    |\n| 在线编写自定义CSS                                                             | ❌     | ✅    |\n| Docker基础管理（开发中）                                                      | ❌     | ✅    |\n| 其他（跟随计划不断开发中）                                                    |        |       |\n\n</div>', 'Pro功能说明');
INSERT INTO `system_setting` (`config_name`, `config_value`, `description`) VALUES ( 'var.donate_reward_description', '亲爱的小伙伴你好，我是 Sun-Panel 的开发者红烧猎人，感谢您一直以来的支持，现推出了Pro功能，对之前用户打赏进行回馈，回馈规则如下：\n\n曾经在 <b><span style=\"color:red\">2024年4月1日前</span></b>   通过以下平台打赏，包括但不仅限于这些平台（支付宝，微信，QQ，B站充电）。请您认真填写以下信息，作者尽量在**24小时内**核对，核对通过后会以邮件的形式下发并通知到您在本平台注册的邮箱。这里有一份 <a target=\"_blank\" style=\"color:blue\" href=\"https://blog.enianteam.com/u/sun/content/259\">打赏名单</a>，未在名单也曾在规定日期打赏过，也可以直接填写以下信息。\n\n| 曾经打赏金额        | 赠送PRO授权时长             | 永久授权                                 |\n| ------------------- | ------------------------ | ---------------------------------------- |\n| 50元以上    | 赠送永久授权（价值99元） |                                          |\n| 30-49元以内 | 10年授权                 | 或加微信（95302870）直接支付30元购买永久 |\n| 10-39元以内 | 5年授权                  | 或加微信（95302870）直接支付50元购买永久 |\n| 1-9元以内   | 2年授权                  | 或加微信（95302870）直接支付60元购买永久 |\n----\n', '捐赠回馈说明');
