INSERT INTO `system_setting` (`config_name`, `config_value`, `description`) VALUES ( 'mdPage.paypal_order_submit_cn', '{\"isLogin\":true,\"content\":\"PayPal的支付方式比较特殊，需要人工审核，所以24小时内才会成功激活，基本信息填写完成请点击保存。\\n\\n\\u003cstyle\\u003e\\nbody,html{\\nbackground:pink;\\n}\\n.dsfjkhadfghd. i{\\nlist-style-type: auto;\\n}\\n\\u003c/style\\u003e\\n\\n基本流程\\n\\n\\u003cdiv style=\\\"list-style-type: auto;\\\" class=\\\"dsfjkhadfghd\\\"\\u003e\\n\\n\\n1.点击下面付款连接进行跳转\\n2.在付款页面进行付款\\n3.付款成功后，将交易号（订单号）复制并回到当前页面粘贴到下面的文本框内\\n4.点击提交，提交后将进行人工审核，24小时内为你开通\\n\\n\\u003c/div\\u003e\\n\\n\",\"messageTemplateFlag\":\"paypal_apply_cn\",\"messageTemplatePosition\":\"bottom\"}', 'Paypal订单提交');
INSERT INTO `sun_pay_test`.`message_template` (`id`, `created_at`, `updated_at`, `deleted_at`, `name`, `flag`, `title`, `title_show`, `title_edit`, `content`, `content_show`, `content_edit`, `note`, `args_json`, `to_usernames`, `to_username_show`, `to_username_edit`, `upload_appendix_show`, `upload_appendix_max`, `upload_appendix_min`, `save_after_url`, `save_button_name`) VALUES (1, '2024-03-12 23:56:38.755', '2024-03-25 19:22:30.100', NULL, 'PayPal支付方式人为激活', 'paypal_apply_cn', 'PayPal支付方式人为激活', 0, 0, '套餐单号：\n{{order}}\nPaypal支付单号：\n{{paypal_order}}\n购买时长（可选：1个月，1个季度，1年，永久）：\n{{duration}}', 0, 0, '', '[{\"keyword\":\"{{paypal_order}}\",\"name\":\"Paypal支付单号\",\"required\":false,\"placeholder\":\"\",\"formType\":\"\"},{\"keyword\":\"{{duration}}\",\"name\":\"购买时长（1个月，1个季度，1年，永久）\",\"required\":false,\"placeholder\":\"\",\"formType\":\"\"},{\"keyword\":\"{{order}}\",\"name\":\"套餐订单号\",\"required\":false,\"placeholder\":\"\",\"formType\":\"\"}]', '95302870@qq.com', 0, 0, 0, 0, 0, '/', '提交');
INSERT INTO `sun_pay_test`.`message_template` (`id`, `created_at`, `updated_at`, `deleted_at`, `name`, `flag`, `title`, `title_show`, `title_edit`, `content`, `content_show`, `content_edit`, `note`, `args_json`, `to_usernames`, `to_username_show`, `to_username_edit`, `upload_appendix_show`, `upload_appendix_max`, `upload_appendix_min`, `save_after_url`, `save_button_name`) VALUES (2, '2024-03-22 10:02:32.526', '2024-03-24 16:44:56.983', NULL, '赞助奖励', 'sponsor_reward_cn', '赞助回馈-用户', 0, 0, '平台：【{{platform}}】\n订单号：【{{order_no}}】\n金额：【{{price}}】', 0, 0, '', '[{\"keyword\":\"{{platform}}\",\"name\":\"打赏平台\",\"required\":true,\"placeholder\":\"示例：支付宝\",\"formType\":\"\"},{\"keyword\":\"{{order_no}}\",\"name\":\"打赏平台的订单号（B站和QQ小伙伴避免冒领填写完信息需要私信我）\",\"required\":true,\"placeholder\":\"必填（b站和QQ填写用户名或者QQ号）\",\"formType\":\"\"},{\"keyword\":\"{{price}}\",\"name\":\"打赏金额\",\"required\":true,\"placeholder\":\"必填并请如实填写\",\"formType\":\"\"}]', '95302870@qq.com', 0, 0, 1, 0, 0, '', '提交');
INSERT INTO `sun_pay_test`.`message_template` (`id`, `created_at`, `updated_at`, `deleted_at`, `name`, `flag`, `title`, `title_show`, `title_edit`, `content`, `content_show`, `content_edit`, `note`, `args_json`, `to_usernames`, `to_username_show`, `to_username_edit`, `upload_appendix_show`, `upload_appendix_max`, `upload_appendix_min`, `save_after_url`, `save_button_name`) VALUES (3, '2024-03-25 12:59:04.153', '2024-03-25 12:59:04.153', NULL, '默认模板', 'default_cn', '', 1, 1, '', 1, 1, '', '[]', '', 1, 1, 1, 5, 0, '/', '发送');
INSERT INTO `email_template` (`created_at`, `updated_at`, `deleted_at`, `name`, `title`, `content`, `note`, `args_json`, `flag`) VALUES ('2024-03-05 18:42:28.000', '2024-03-07 11:32:57.306', NULL, '验证码模板【CN】', '您正在{THING}，需要验证', '<meta charset=\"utf-8\">\n<table width=\"600px\"  style=\"max-width: 600px;\" align=\"center\">\n    <tr style=\"width: 600px;background-color: rgb(28, 197, 249);\">\n        <td align=\"left\" style=\"width: 600px;padding: 22px 18px 11px;display: inline-block;\">\n            <div style=\"font-weight: 900;font-size: 18px;\">\n                <p>Hi {NICKNAME}:</p>\n            </div>\n        </td>\n        <td style=\"width: 100%;display: inline-block;border-top: 4px dashed rgb(255, 255, 255);\"> </td>\n        <td style=\"width: 600px;padding: 18px;display: inline-block;\">\n			<div align=\"left\" style=\"color: rgb(57, 57, 57); line-height: 1.6; font-size: 14px; margin: 0px;font-weight: bolder;\">\n                您正在{THING}，以下是您所需的验证码：\n                <p><div style=\"color: #fff;background-color: #2e2e2e;display: inline-block;padding: 10px 30px;border-radius: 5px;\">{VCODE}</div></p>\n			</div>\n        </td>\n        <td style=\"width: 600px;padding: 18px;display: inline-block;\">\n            <div align=\"rignt\">\n                <div style=\"font-size: 14px; margin: 0px;text-align: right;font-size: 14px; font-weight: bolder;\">\n                    --  来自[<a href=\"{URL}\" style=\"color: #575757;\">Sun-Panel</a>]</div>\n            </div>\n        </td>\n    </tr>\n</table>', '', '[{\"keyword\":\"{THING}\",\"name\":\"注册\"},{\"keyword\":\"{VCODE}\",\"name\":\"验证码\"}]', 'verification_code_cn');
INSERT INTO `email_template` (`created_at`, `updated_at`, `deleted_at`, `name`, `title`, `content`, `note`, `args_json`, `flag`) VALUES ('2024-03-05 22:14:09.761', '2024-03-06 12:32:01.645', NULL, '注册站点成功【CN】', '你已成功注册[Sun-Panel]的订阅站', 'Hi，{EMAIL}\n欢迎的加入[Sun-Panel]订阅站，希望在今后的日子里，一直有你陪伴！', '', '[{\"keyword\":\"{EMAIL}\",\"name\":\"邮箱号\"}]', ' register_success_cn');
INSERT INTO `email_template` (`created_at`, `updated_at`, `deleted_at`, `name`, `title`, `content`, `note`, `args_json`, `flag`) VALUES ('2024-03-05 23:52:45.561', '2024-03-06 12:22:53.276', NULL, 'Beta更新说明【CN】', 'Sun-Panel Beta版本更新了{VERSION}', '你好，我的小伙伴：\nSun-Panel更新了一个beta的版本，版本号：{VERSION}，欢迎您前往更新并体验，如果遇到问题和建议欢迎提出Issue，另外我们可以前往社区进行交流！', '', '[{\"keyword\":\"{VERSION}\",\"name\":\"版本号\"}]', 'beta_update_cn');
INSERT INTO `email_template` (`created_at`, `updated_at`, `deleted_at`, `name`, `title`, `content`, `note`, `args_json`, `flag`) VALUES ('2024-03-06 12:55:08.015', '2024-03-06 12:55:08.015', NULL, '通用模板', '--', '<meta charset=\"utf-8\">\n<table width=\"600px\"  style=\"max-width: 600px;\" align=\"center\">\n    <tr style=\"width: 600px;background-color: rgb(28, 197, 249);\">\n        <td align=\"left\" style=\"width: 600px;padding: 22px 18px 11px;display: inline-block;\">\n            <div style=\"font-weight: 900;font-size: 18px;\">\n                <p>Hi {NICKNAME}:</p>\n            </div>\n        </td>\n        <td style=\"width: 100%;display: inline-block;border-top: 4px dashed rgb(255, 255, 255);\"> </td>\n        <td style=\"width: 600px;padding: 18px;display: inline-block;\">\n			<div align=\"left\" style=\"color: rgb(57, 57, 57); line-height: 1.6; font-size: 14px; margin: 0px;font-weight: bolder;\">\n					{CONTENT}\n			</div>\n        </td>\n        <td style=\"width: 600px;padding: 18px;display: inline-block;\">\n            <div align=\"rignt\">\n                <div style=\"font-size: 14px; margin: 0px;text-align: right;font-size: 14px; font-weight: bolder;\">\n                    --  来自[<a href=\"{URL}\" style=\"color: #575757;\">Sun-Panel</a>]</div>\n            </div>\n        </td>\n    </tr>\n</table>', '', '[{\"keyword\":\"{URL}\",\"name\":\"回调地址\"},{\"keyword\":\"{CONTENT}\",\"name\":\"内容\"},{\"keyword\":\"{NICKNAME}\",\"name\":\"昵称\"}]', 'tongyong_cn');
INSERT INTO `email_template` (`created_at`, `updated_at`, `deleted_at`, `name`, `title`, `content`, `note`, `args_json`, `flag`) VALUES ('2024-03-06 21:05:47.007', '2024-03-06 22:29:00.398', NULL, '用户打赏回赠奖励【CN】', '[Sun-Panel] 感谢您曾经的捐赠，现回赠您Pro版本的激活码，有效期时长为{TIME}', '首先感谢您对项目和作者的支持，经过核查，您曾经的捐赠有效，现对您进行回赠Pro功能的激活码。有效期时长为{TIME}，从今天24时开始计算，请前往【平台】登录账号后查看和使用。\n', '', '[{\"keyword\":\"{TIME}\",\"name\":\"3天/月/年/季度/永久\"}]', 'donate_award_cn');
INSERT INTO `email_template` (`created_at`, `updated_at`, `deleted_at`, `name`, `title`, `content`, `note`, `args_json`, `flag`) VALUES ('2024-03-06 21:20:03.673', '2024-03-06 22:28:40.185', NULL, '推广奖励', '感谢您的推广，现回赠您Pro版激活码，有效时长为{TIME}', '感谢您的推广，现回赠您Pro版激活码。有效时长为{TIME}，从今天24时开始计算，请前往【平台】进行查看', '', '[{\"keyword\":\"{TIME}\",\"name\":\"有效时长\"}]', 'promotion_reward_cn');
